const body = $json.body || $json;
const raw = (body.content || body.message || '').trim();

// Comandos soportados:
// !fase listar
// !fase add <nombre> <fecha_inicio YYYY-MM-DD> <fecha_fin YYYY-MM-DD> [responsable]
// !fase edit <list_id> nombre=<nuevo_nombre> fin=<YYYY-MM-DD> responsable=<nombre>
// !fase delete <list_id>
// !fase sync   <- sincroniza listas Trello -> BD
// !doc <card_id> <- extrae resumen del PDF adjunto a una tarjeta

const docMatch = raw.match(/^!doc\s+(\S+)/i);
if (docMatch) {
  return [{ json: { action: 'doc_summary', card_id: docMatch[1], raw } }];
}

const match = raw.match(/^!fase\s+(\S+)(?:\s+(.*))?$/i);
if (!match) {
  return [{ json: { action: 'unknown', raw } }];
}

const subCmd = match[1].toLowerCase();
const rest = (match[2] || '').trim();

if (subCmd === 'listar') {
  return [{ json: { action: 'list', raw } }];
}

if (subCmd === 'sync') {
  return [{ json: { action: 'sync', raw } }];
}

if (subCmd === 'add') {
  const parts = rest.split(/\s+/);
  if (parts.length < 3) {
    return [{ json: { action: 'error', message: '⚠️ Uso: `!fase add <nombre> <inicio YYYY-MM-DD> <fin YYYY-MM-DD> [responsable]`', raw } }];
  }
  const start_date = parts[parts.length - 2];
  const end_date = parts[parts.length - 1];
  const dateRe = /^\d{4}-\d{2}-\d{2}$/;
  if (!dateRe.test(start_date) || !dateRe.test(end_date)) {
    return [{ json: { action: 'error', message: '⚠️ Fechas inválidas. Usa formato YYYY-MM-DD', raw } }];
  }
  const name = parts.slice(0, parts.length - 2).join(' ');
  return [{ json: { action: 'add', name, start_date, end_date, raw } }];
}

if (subCmd === 'edit') {
  const parts = rest.split(/\s+/);
  const list_id = parts[0];
  const kvs = {};
  parts.slice(1).forEach(p => {
    const [k, v] = p.split('=');
    if (k && v) kvs[k] = v;
  });
  return [{ json: { action: 'edit', list_id, updates: kvs, raw } }];
}

if (subCmd === 'delete') {
  return [{ json: { action: 'delete', list_id: rest, raw } }];
}

return [{ json: { action: 'unknown', raw } }];

const phases = $input.all().map(item => item.json);
if (phases.length === 0) {
  return [{ json: { content: '📋 No hay fases registradas. Usa `!fase sync` para sincronizar desde Trello.' } }];
}

const statusEmoji = { active: '🔵', completed: '✅', on_hold: '⏸️' };
const lines = ['📋 **Fases del Proyecto PetSafe**', ''];

phases.forEach((p, i) => {
  const pct = p.total_cards > 0 ? Math.round((p.done_cards / p.total_cards) * 100) : 0;
  const bar = '█'.repeat(Math.floor(pct / 10)) + '░'.repeat(10 - Math.floor(pct / 10));
  const emoji = statusEmoji[p.status] || '⚪';
  lines.push(`${emoji} **${i + 1}. ${p.name}**`);
  if (p.start_date && p.end_date) lines.push(`   📅 ${p.start_date} → ${p.end_date}`);
  if (p.responsible) lines.push(`   👤 ${p.responsible}`);
  lines.push(`   ${bar} ${pct}% (${p.done_cards}/${p.total_cards} tarjetas)`);
  lines.push(`   ID: \`${p.list_id}\``);
  lines.push('');
});

return [{ json: { content: lines.join('\n').slice(0, 2000) } }];

const lists = $input.all().map(item => item.json).filter(l => !l.closed);
const upserts = lists.map((l, idx) => [
  l.id, l.name, idx + 1
]);
return upserts.map((row, idx) => ({ json: { list_id: row[0], name: row[1], position: row[2] } }));

const ctx = $('Parse Phase Command').item.json;
const updates = ctx.updates || {};
const setClauses = [];
const params = [ctx.list_id];
let idx = 2;
if (updates.nombre) { setClauses.push(`name = $${idx++}`); params.push(updates.nombre); }
if (updates.fin) { setClauses.push(`end_date = $${idx++}`); params.push(updates.fin); }
if (updates.inicio) { setClauses.push(`start_date = $${idx++}`); params.push(updates.inicio); }
if (updates.responsable) { setClauses.push(`responsible = $${idx++}`); params.push(updates.responsable); }
if (updates.estado) { setClauses.push(`status = $${idx++}`); params.push(updates.estado); }

if (setClauses.length === 0) {
  return [{ json: { skip: true, content: '⚠️ No se especificaron campos a actualizar.' } }];
}

return [{
  json: {
    query: `UPDATE project_phases SET ${setClauses.join(', ')}, updated_at = NOW() WHERE list_id = $1 RETURNING name, list_id;`,
    params: JSON.stringify(params),
    list_id: ctx.list_id
  }
}];

const attachment = $('Fetch Card Attachments').first()?.json || {};
const summary = $json.text || attachment.summary_extracted || 'Sin resumen disponible';
const kb = Math.round((attachment.file_size_bytes || 0) / 1024);
const content = `📎 **${attachment.filename}** (${kb} KB)\n\n${summary}\n\n*Resumen generado por IA — extrae sólo metadatos y contexto*`;
return [{ json: { content: content.slice(0, 2000) } }];

const action = $('Parse Phase Command').item.json.action;
const phase = $json;
let content = '';

if (action === 'add') {
  content = `✅ **Fase creada:** \`${phase.name}\`\n📅 ${phase.start_date} → ${phase.end_date}\nID: \`${phase.list_id}\`\n\n💡 Tip: Usa \`!fase sync\` para vincularla con Trello si ya existe la lista.`;
} else if (action === 'edit') {
  content = `✏️ **Fase actualizada:** \`${phase.name}\`\nID: \`${phase.list_id}\``;
} else if (action === 'delete') {
  content = `🗑️ **Fase archivada:** \`${phase.name}\`\n*Las tarjetas existentes no fueron afectadas.*`;
} else if (action === 'sync') {
  content = `🔄 **Sincronización completada.** Las listas de Trello fueron importadas a la BD.`;
} else {
  content = $json.content || $json.message || 'Acción desconocida.';
}
return [{ json: { content } }];
